class ErrorEscalationState(TypedDict):
    query: str
    response: str
    error: str       # empty = success; non-empty = escalate
    tier: int


def tier1_with_error_handling(state: ErrorEscalationState) -> dict:
    try:
        response = _fast_llm.invoke(state["query"])
        return {"response": response.content, "error": "", "tier": 1}
    except Exception as exc:
        return {
            "response": "",
            "error": f"tier1 failed: {exc}",
            "tier": 1,
        }


def route_by_error(state: ErrorEscalationState) -> str:
    if state["error"]:
        return "tier2_specialist"
    return END


def tier2_with_error_handling(state: ErrorEscalationState) -> dict:
    try:
        prompt = f"Previous attempt failed: {state['error']}\nQuery: {state['query']}"
        response = _specialist_llm.invoke(prompt)
        return {"response": response.content, "error": "", "tier": 2}
    except Exception as exc:
        return {
            "response": "",
            "error": f"tier2 also failed: {exc}",
            "tier": 2,
        }

from dataclasses import dataclass
from collections import defaultdict


@dataclass
class EscalationMetrics:
    total: int = 0
    resolved_tier1: int = 0
    resolved_tier2: int = 0
    resolved_human: int = 0
    failed: int = 0

    def record(self, tier: int, success: bool) -> None:
        self.total += 1
        if not success:
            self.failed += 1
            return
        if tier == 1:
            self.resolved_tier1 += 1
        elif tier == 2:
            self.resolved_tier2 += 1
        else:
            self.resolved_human += 1

    def escalation_rate(self) -> float:
        """Fraction of queries that needed tier 2 or higher."""
        return (self.resolved_tier2 + self.resolved_human) / max(self.total, 1)

    def human_escalation_rate(self) -> float:
        return self.resolved_human / max(self.total, 1)


_metrics = EscalationMetrics()


def instrumented_tier1(state: EscalationState) -> dict:
    result = tier1_fast(state)
    _metrics.record(1, result["confidence"] >= CONFIDENCE_THRESHOLD_T1)
    return result
